   148→func singleUpdate(c Client, apiserverID string, gr schema.GroupResource, encodingVersion string, decodableVersions []string, servedVersions []string) error {
   149→	shouldCreate := false
   150→	name := fmt.Sprintf("%s.%s", gr.Group, gr.Resource)
   151→	sv, err := c.Get(context.TODO(), name, metav1.GetOptions{})
   152→	if err != nil && !apierrors.IsNotFound(err) {
   153→		return err
   154→	}
   155→	if apierrors.IsNotFound(err) {
   156→		shouldCreate = true
   157→		sv = &v1alpha1.StorageVersion{}
   158→		sv.ObjectMeta.Name = name
   159→	}
   160→	updatedSV := localUpdateStorageVersion(sv, apiserverID, encodingVersion, decodableVersions, servedVersions)
   161→	if shouldCreate {
   162→		createdSV, err := c.Create(context.TODO(), updatedSV, metav1.CreateOptions{})
   163→		if err != nil {
   164→			return err
   165→		}
   166→		// assign the calculated status to the object just created, then update status
   167→		createdSV.Status = updatedSV.Status
   168→		_, err = c.UpdateStatus(context.TODO(), createdSV, metav1.UpdateOptions{})
   169→		return err
   170→	}
   171→	_, err = c.UpdateStatus(context.TODO(), updatedSV, metav1.UpdateOptions{})
   172→	return err
   173→}
