   175→// localUpdateStorageVersion updates the input storageversion with given server storageversion info.
   176→// The function updates the input storageversion in place.
   177→func localUpdateStorageVersion(sv *v1alpha1.StorageVersion, apiserverID, encodingVersion string, decodableVersions []string, servedVersions []string) *v1alpha1.StorageVersion {
   178→	newSSV := v1alpha1.ServerStorageVersion{
   179→		APIServerID:       apiserverID,
   180→		EncodingVersion:   encodingVersion,
   181→		DecodableVersions: decodableVersions,
   182→		ServedVersions:    servedVersions,
   183→	}
   184→	foundSSV := false
   185→	for i, ssv := range sv.Status.StorageVersions {
   186→		if ssv.APIServerID == apiserverID {
   187→			sv.Status.StorageVersions[i] = newSSV
   188→			foundSSV = true
   189→			break
   190→		}
   191→	}
   192→	if !foundSSV {
   193→		sv.Status.StorageVersions = append(sv.Status.StorageVersions, newSSV)
   194→	}
   195→	SetCommonEncodingVersion(sv)
   196→	return sv
   197→}
